public class WordLadder { public static int ladderLength(String start, String end, java.util.List<String> dict) { java.util.Queue<String> queue = new java.util.LinkedList<>(); java.util.Set<String> visited = new java.util.HashSet<>(dict); queue.offer(start); int level = 1; while(!queue.isEmpty()) { int size = queue.size(); for(int i = 0; i < size; i++) { String curr = queue.poll(); if(curr.equals(end)) return level; for(String word : dict) if(!visited.contains(word) && isAdjacent(curr, word)) { queue.offer(word); visited.remove(word); } } level++; } return 0; } }